import anthropic

client = anthropic.Anthropic()

def compress_turn(
    turn: dict,                 # {'role': ..., 'content': ...}
    target_tokens: int = 200,
) -> dict:
    content = turn.get('content', '')
    if not isinstance(content, str) or len(content.split()) < 80:
        return turn  # too short to benefit from compression

    response = client.messages.create(
        model='claude-haiku-4-5-20251001',
        max_tokens=target_tokens,
        messages=[{'role': 'user', 'content': (
            f'Compress the following {turn["role"]} message to under {target_tokens // 4} words. '
            f'Preserve all facts, numbers, decisions, and named entities. '
            f'Remove filler, repetition, and verbose phrasing.\n\n{content}'
        )}],
    )
    compressed_text = response.content[0].text
    return {'role': turn['role'], 'content': f'[compressed] {compressed_text}'}

def compress_history(
    messages: list[dict],
    max_history_tokens: int = 30_000,
    compress_older_than: int = 4,   # compress turns beyond this recency
) -> list[dict]:
    import tiktoken
    enc = tiktoken.get_encoding('cl100k_base')

    def count(msgs):
        return sum(len(enc.encode(str(m.get('content', '')))) + 4 for m in msgs)

    if count(messages) <= max_history_tokens:
        return messages

    # Compress older turns, keep recent turns verbatim
    recent  = messages[-compress_older_than:]
    to_compress = messages[:-compress_older_than]

    compressed = [compress_turn(m) for m in to_compress]
    return compressed + recent

# Structured distillation: extract typed facts from conversation into compact JSON
# The JSON payload replaces verbose conversation turns with a queryable fact store
import anthropic, json

client = anthropic.Anthropic()

# Schema for extracted facts — domain-specific
FACT_SCHEMA = {
    'decisions':   'list of decisions made (string each)',
    'facts':       'list of factual claims established (string each)',
    'preferences': 'list of user preferences or constraints (string each)',
    'open_items':  'list of unresolved questions or tasks (string each)',
}

def distill_to_facts(
    messages: list[dict],
) -> dict:
    conversation = '\n'.join(
        f"{m['role'].upper()}: {m.get('content', '')[:500]}"
        for m in messages if isinstance(m.get('content'), str)
    )
    response = client.messages.create(
        model='claude-haiku-4-5-20251001',
        max_tokens=600,
        messages=[{'role': 'user', 'content': (
            f'Extract structured facts from this conversation. '
            f'Return ONLY valid JSON matching: {json.dumps(FACT_SCHEMA)}.\n\n{conversation}'
        )}],
    )
    try:
        return json.loads(response.content[0].text)
    except json.JSONDecodeError:
        # Fallback: return raw text as a single fact
        return {'facts': [response.content[0].text], 'decisions': [], 'preferences': [], 'open_items': []}

def facts_to_context_message(facts: dict) -> dict:
    lines = []
    for category, items in facts.items():
        if items:
            lines.append(f'**{category.title()}**')
            lines.extend(f'- {item}' for item in items)
    return {
        'role': 'user',
        'content': '[Distilled context]\n' + '\n'.join(lines),
    }

# Selective deletion: score messages by value and drop the lowest-scoring ones
# Use when you cannot afford an LLM call for summarization (latency budget)
import re

def score_message(msg: dict) -> float:
    content = msg.get('content', '')
    if not isinstance(content, str):
        return 1.0  # tool messages always valuable

    score = 0.5  # baseline

    # Boost for high-signal content
    if re.search(r'\d+\.?\d*%|\$\d+|\d+ (days|weeks|hours)', content):
        score += 0.3  # numbers / measurements
    if re.search(r'\b(decided|agreed|confirmed|will|must|never|always)\b', content, re.I):
        score += 0.2  # commitment language
    if re.search(r'\b(error|failed|exception|bug|issue)\b', content, re.I):
        score += 0.2  # diagnostic value

    # Penalize low-signal content
    if len(content.split()) < 15:
        score -= 0.2  # very short messages
    if re.match(r'^(sure|ok|got it|understood|thanks)', content.strip(), re.I):
        score -= 0.4  # acknowledgement-only

    return max(0.0, min(1.0, score))

def selective_delete(
    messages: list[dict],
    target_tokens: int,
) -> list[dict]:
    import tiktoken
    enc = tiktoken.get_encoding('cl100k_base')
    def count(msgs): return sum(len(enc.encode(str(m.get('content', '')))) + 4 for m in msgs)

    if count(messages) <= target_tokens:
        return messages

    # Score each message, always keep last 4 turns verbatim
    recent = messages[-4:]
    candidates = list(enumerate(messages[:-4]))
    candidates.sort(key=lambda x: score_message(x[1]))  # lowest score first

    retained = set(range(len(messages) - 4, len(messages)))  # recent always kept
    for idx, _ in candidates:
        retained.add(idx)
        if count([m for i, m in enumerate(messages) if i in retained]) <= target_tokens:
            break

    result = [m for i, m in enumerate(messages) if i in retained]
    # Re-validate alternating structure
    if result and result[0]['role'] != 'user':
        result = result[1:]  # trim leading non-user message
    return result

# Rolling compression manager: compress proactively on a schedule,
# not just when the budget is exceeded
import anthropic, tiktoken
from dataclasses import dataclass, field

enc = tiktoken.get_encoding('cl100k_base')
client = anthropic.Anthropic()

@dataclass
class RollingCompressor:
    max_tokens:       int = 40_000
    compress_at:      float = 0.75  # compress when window hits 75% full
    keep_verbatim:    int = 6       # keep last N messages as-is
    _messages: list[dict] = field(default_factory=list)

    def _count(self) -> int:
        return sum(len(enc.encode(str(m.get('content', '')))) + 4 for m in self._messages)

    def add(self, role: str, content: str) -> None:
        self._messages.append({'role': role, 'content': content})
        if self._count() > self.max_tokens * self.compress_at:
            self._compress()

    def _compress(self) -> None:
        if len(self._messages) <= self.keep_verbatim:
            return
        recent  = self._messages[-self.keep_verbatim:]
        to_compress = self._messages[:-self.keep_verbatim]

        # Build combined text for all turns to compress
        combined = '\n'.join(
            f"{m['role'].upper()}: {m.get('content', '')}"
            for m in to_compress if isinstance(m.get('content'), str)
        )
        response = client.messages.create(
            model='claude-haiku-4-5-20251001',
            max_tokens=400,
            messages=[{'role': 'user', 'content': (
                'Summarize the following conversation in 5–8 bullet points. '
                'Capture all decisions, commitments, and factual claims. '
                f'Omit greetings and filler.\n\n{combined[:4000]}'
            )}],
        )
        summary = response.content[0].text

        # Replace compressed turns with a single summary message pair
        self._messages = [
            {'role': 'user',      'content': f'[Session summary]\n{summary}'},
            {'role': 'assistant', 'content': 'Understood, I have this context.'},
        ] + recent

    def messages(self) -> list[dict]:
        return list(self._messages)

    @property
    def utilization(self) -> float:
        return self._count() / self.max_tokens
